<div class="page-header"><div><h2>Company Context Switch</h2><p>Super admins can safely preview tenant data without changing ownership or credentials.</p></div></div>
<div class="card"><form method="post" class="stack-form"><?= csrf_field() ?><select name="company_id"><option value="1">Primary Company Context</option><?php foreach ($companies as $company): ?><option value="<?= e((string)$company['id']) ?>" <?= ((int)$activeCompanyId === (int)$company['id']) ? 'selected' : '' ?>><?= e($company['company_name']) ?><?= !empty($company['company_slug']) ? ' · ' . e($company['company_slug']) : '' ?></option><?php endforeach; ?></select><button type="submit">Switch Context</button></form></div>